export { sanitizeHref } from "./sanitize-href";

/**
 * Sanitize a URL to ensure it's safe for use in href attributes.
 * Only allows http: and https: protocols.
 *
 * @returns The sanitized URL string, or undefined if invalid/unsafe
 */
export function sanitizeHref(href?: string): string | undefined {
  if (!href) return undefined;
  try {
    const url = new URL(href);
    if (url.protocol === "http:" || url.protocol === "https:") {
      return url.toString();
    }
  } catch {
    return undefined;
  }
  return undefined;
}

import { z } from "zod";

function formatZodPath(path: Array<string | number | symbol>): string {
  if (path.length === 0) return "root";
  return path
    .map((segment) =>
      typeof segment === "number" ? `[${segment}]` : String(segment),
    )
    .join(".");
}

/**
 * Format Zod errors into a compact `path: message` string.
 */
export function formatZodError(error: z.ZodError): string {
  const parts = error.issues.map((issue) => {
    const path = formatZodPath(issue.path);
    return `${path}: ${issue.message}`;
  });

  return Array.from(new Set(parts)).join("; ");
}

/**
 * Parse unknown input and throw a readable error.
 */
export function parseWithSchema<T>(
  schema: z.ZodType<T>,
  input: unknown,
  name: string,
): T {
  const res = schema.safeParse(input);
  if (!res.success) {
    throw new Error(`Invalid ${name} payload: ${formatZodError(res.error)}`);
  }
  return res.data;
}

/**
 * Parse unknown input, returning `null` instead of throwing on failure.
 *
 * Use this in assistant-ui `render` functions where `args` stream in
 * incrementally and may be incomplete until the tool call finishes.
 */
export function safeParseWithSchema<T>(
  schema: z.ZodType<T>,
  input: unknown,
): T | null {
  const res = schema.safeParse(input);
  return res.success ? res.data : null;
}

import { z } from "zod";
import type { ReactNode } from "react";

/**
 * Tool UI conventions:
 * - Serializable schemas are JSON-safe (no callbacks/ReactNode/`className`).
 * - Schema: `SerializableXSchema`
 * - Parser: `parseSerializableX(input: unknown)` (throws on invalid)
 * - Safe parser: `safeParseSerializableX(input: unknown)` (returns `null` on invalid — use in streaming render functions)
 * - Render helper: `resolveStreamingToolRenderState(...)` (normalizes loading/partial/ready/error states)
 * - Render UI: `<ToolRenderState state={state} />` (shared loading/partial/error affordances)
 * - Actions: `responseActions`, `onResponseAction`, `onBeforeResponseAction`
 * - Root attrs: `data-tool-ui-id` + `data-slot`
 */

/**
 * Schema for tool UI identity.
 *
 * Every tool UI should have a unique identifier that:
 * - Is stable across re-renders
 * - Is meaningful (not auto-generated)
 * - Is unique within the conversation
 *
 * Format recommendation: `{component-type}-{semantic-identifier}`
 * Examples: "data-table-expenses-q3", "option-list-deploy-target"
 */
export const ToolUIIdSchema = z.string().min(1);

export type ToolUIId = z.infer<typeof ToolUIIdSchema>;

/**
 * Primary role of a Tool UI surface in a chat context.
 */
export const ToolUIRoleSchema = z.enum([
  "information",
  "decision",
  "control",
  "state",
  "composite",
]);

export type ToolUIRole = z.infer<typeof ToolUIRoleSchema>;

export const ToolUIReceiptOutcomeSchema = z.enum([
  "success",
  "partial",
  "failed",
  "cancelled",
]);

export type ToolUIReceiptOutcome = z.infer<typeof ToolUIReceiptOutcomeSchema>;

/**
 * Optional receipt metadata: a durable summary of an outcome.
 */
export const ToolUIReceiptSchema = z.object({
  outcome: ToolUIReceiptOutcomeSchema,
  summary: z.string().min(1),
  identifiers: z.record(z.string(), z.string()).optional(),
  at: z.string().datetime(),
});

export type ToolUIReceipt = z.infer<typeof ToolUIReceiptSchema>;

/**
 * Base schema for Tool UI payloads (id + optional role/receipt).
 */
export const ToolUISurfaceSchema = z.object({
  id: ToolUIIdSchema,
  role: ToolUIRoleSchema.optional(),
  receipt: ToolUIReceiptSchema.optional(),
});

export type ToolUISurface = z.infer<typeof ToolUISurfaceSchema>;

export const ActionSchema = z.object({
  id: z.string().min(1),
  label: z.string().min(1),
  /**
   * Canonical narration the assistant can use after this action is taken.
   *
   * Example: "I exported the table as CSV." / "I opened the link in a new tab."
   */
  sentence: z.string().optional(),
  confirmLabel: z.string().optional(),
  variant: z
    .enum(["default", "destructive", "secondary", "ghost", "outline"])
    .optional(),
  icon: z.custom<ReactNode>().optional(),
  loading: z.boolean().optional(),
  disabled: z.boolean().optional(),
  shortcut: z.string().optional(),
});

export type Action = z.infer<typeof ActionSchema>;

export const ActionButtonsPropsSchema = z.object({
  actions: z.array(ActionSchema).min(1),
  align: z.enum(["left", "center", "right"]).optional(),
  confirmTimeout: z.number().positive().optional(),
  className: z.string().optional(),
});

export const SerializableActionSchema = ActionSchema.omit({ icon: true });
export const SerializableActionsSchema = ActionButtonsPropsSchema.extend({
  actions: z.array(SerializableActionSchema),
}).omit({ className: true });

export interface ActionsConfig {
  items: Action[];
  align?: "left" | "center" | "right";
  confirmTimeout?: number;
}

export const SerializableActionsConfigSchema = z.object({
  items: z.array(SerializableActionSchema).min(1),
  align: z.enum(["left", "center", "right"]).optional(),
  confirmTimeout: z.number().positive().optional(),
});

export type SerializableActionsConfig = z.infer<
  typeof SerializableActionsConfigSchema
>;

export type SerializableAction = z.infer<typeof SerializableActionSchema>;

export type SafeParser<T> = (input: unknown) => T | null;
/**
 * Structural status shape used by streaming render helpers.
 *
 * This intentionally avoids coupling to a specific runtime package while
 * remaining compatible with assistant-ui tool call statuses.
 */
export interface StreamingToolStatus {
  type: string;
  reason?: string;
  error?: unknown;
}

export type StreamingToolRenderState<TArgs, TResult> =
  | {
      kind: "loading";
      args: TArgs | null;
      result: null;
      message: string;
      status: StreamingToolStatus;
    }
  | {
      kind: "partial";
      args: TArgs | null;
      result: TResult;
      status: StreamingToolStatus;
    }
  | {
      kind: "ready";
      args: TArgs | null;
      result: TResult;
      status: StreamingToolStatus;
    }
  | {
      kind: "error";
      args: TArgs | null;
      result: null;
      message: string;
      isCancelled: boolean;
      status: StreamingToolStatus;
    };

export interface ResolveStreamingToolRenderStateOptions<TArgs, TResult> {
  status: StreamingToolStatus;
  args?: unknown;
  result?: unknown;
  safeParseArgs?: SafeParser<TArgs>;
  safeParseResult?: SafeParser<TResult>;
  loadingMessage?: string;
  awaitingActionMessage?: string;
  unavailableMessage?: string;
  cancelledMessage?: string;
  errorMessage?: string;
}

const DEFAULT_LOADING_MESSAGE = "Loading…";
const DEFAULT_AWAITING_ACTION_MESSAGE = "Awaiting input…";
const DEFAULT_UNAVAILABLE_MESSAGE = "Tool output unavailable";
const DEFAULT_CANCELLED_MESSAGE = "Tool call cancelled";
const DEFAULT_ERROR_MESSAGE = "Tool failed";

function stringifyError(error: unknown): string | null {
  if (typeof error === "string") return error;
  if (error == null) return null;
  try {
    return JSON.stringify(error);
  } catch {
    return String(error);
  }
}

/**
 * Normalize streamed tool-part args/result into a UI-safe render state.
 *
 * - Use safe parsers so partial payloads don't throw while streaming.
 * - Distinguishes loading/partial/ready/error phases for consistent fallback UI.
 */
export function resolveStreamingToolRenderState<TArgs, TResult>(
  options: ResolveStreamingToolRenderStateOptions<TArgs, TResult>,
): StreamingToolRenderState<TArgs, TResult> {
  const {
    status,
    args,
    result,
    safeParseArgs,
    safeParseResult,
    loadingMessage = DEFAULT_LOADING_MESSAGE,
    awaitingActionMessage = DEFAULT_AWAITING_ACTION_MESSAGE,
    unavailableMessage = DEFAULT_UNAVAILABLE_MESSAGE,
    cancelledMessage = DEFAULT_CANCELLED_MESSAGE,
    errorMessage = DEFAULT_ERROR_MESSAGE,
  } = options;

  const parsedArgs =
    args === undefined
      ? null
      : safeParseArgs
        ? safeParseArgs(args)
        : (args as TArgs);

  const parsedResult =
    result === undefined
      ? null
      : safeParseResult
        ? safeParseResult(result)
        : (result as TResult);

  if (status.type === "incomplete") {
    const isCancelled = status.reason === "cancelled";
    const baseMessage = isCancelled ? cancelledMessage : errorMessage;
    const statusError = stringifyError(status.error);

    return {
      kind: "error",
      args: parsedArgs,
      result: null,
      message: statusError ? `${baseMessage}: ${statusError}` : baseMessage,
      isCancelled,
      status,
    };
  }

  if (parsedResult !== null) {
    if (status.type === "running" || status.type === "requires-action") {
      return {
        kind: "partial",
        args: parsedArgs,
        result: parsedResult,
        status,
      };
    }

    return {
      kind: "ready",
      args: parsedArgs,
      result: parsedResult,
      status,
    };
  }

  if (status.type === "running") {
    return {
      kind: "loading",
      args: parsedArgs,
      result: null,
      message: loadingMessage,
      status,
    };
  }

  if (status.type === "requires-action") {
    return {
      kind: "loading",
      args: parsedArgs,
      result: null,
      message: awaitingActionMessage,
      status,
    };
  }

  return {
    kind: "error",
    args: parsedArgs,
    result: null,
    message: unavailableMessage,
    isCancelled: false,
    status,
  };
}

"use client";

import { AlertCircle, Loader2, Sparkles } from "lucide-react";
import type { ComponentPropsWithoutRef } from "react";

import { cn } from "./_adapter";
import type { StreamingToolRenderState } from "./streaming-render";

type SharedStreamingState = StreamingToolRenderState<unknown, unknown>;

export interface ToolRenderStateProps
  extends Omit<ComponentPropsWithoutRef<"div">, "children"> {
  state: SharedStreamingState;
  partialLabel?: string;
}

function statusLabel(state: SharedStreamingState): string {
  if (state.kind === "error") {
    if (
      state.isCancelled ||
      (state.status.type === "incomplete" && state.status.reason === "cancelled")
    ) {
      return "Cancelled";
    }
    return "Failed";
  }

  if (state.kind === "loading") {
    return state.status.type === "requires-action"
      ? "Awaiting Input"
      : "Working";
  }

  if (state.kind === "partial") {
    return "Streaming";
  }

  return "Complete";
}

/**
 * Shared render-state status UI for assistant-ui toolkit render functions.
 *
 * - `loading` / `error`: full status card for placeholder/fallback states.
 * - `partial`: compact badge (for streamed partial output while rendering).
 * - `ready`: renders `null`.
 */
export function ToolRenderState({
  state,
  className,
  partialLabel = "Streaming partial output",
  ...props
}: ToolRenderStateProps) {
  if (state.kind === "ready") {
    return null;
  }

  if (state.kind === "partial") {
    return (
      <div
        className={cn(
          "bg-muted/70 text-muted-foreground inline-flex items-center gap-2 rounded-full border px-3 py-1 text-xs",
          className,
        )}
        data-slot="streaming-state"
        data-tool-ui-streaming-state="partial"
        role="status"
        aria-live="polite"
        {...props}
      >
        <Sparkles className="size-3.5" aria-hidden="true" />
        <span>{partialLabel}</span>
      </div>
    );
  }

  const isError = state.kind === "error";
  const Icon = isError ? AlertCircle : Loader2;

  return (
    <div
      className={cn(
        "bg-card/60 flex w-full min-w-80 max-w-md flex-col gap-2 rounded-2xl border px-5 py-4 shadow-xs",
        isError && "border-destructive/30",
        className,
      )}
      data-slot="streaming-state"
      data-tool-ui-streaming-state={state.kind}
      role={isError ? "alert" : "status"}
      aria-live={isError ? "assertive" : "polite"}
      {...props}
    >
      <div className="flex items-center gap-2">
        <Icon
          className={cn("size-4", isError ? "text-destructive" : "animate-spin")}
          aria-hidden="true"
        />
        <p
          className={cn(
            "text-sm font-medium",
            isError ? "text-destructive" : "text-foreground",
          )}
        >
          {statusLabel(state)}
        </p>
      </div>
      <p className="text-muted-foreground text-sm">{state.message}</p>
    </div>
  );
}

"use client";

import { useCallback, useEffect, useMemo, useState } from "react";
import type { Action } from "./schema";

export type UseActionButtonsOptions = {
  actions: Action[];
  onAction: (actionId: string) => void | Promise<void>;
  onBeforeAction?: (actionId: string) => boolean | Promise<boolean>;
  confirmTimeout?: number;
};

export type UseActionButtonsResult = {
  actions: Array<
    Action & {
      currentLabel: string;
      isConfirming: boolean;
      isExecuting: boolean;
      isDisabled: boolean;
      isLoading: boolean;
    }
  >;
  runAction: (actionId: string) => Promise<void>;
  confirmingActionId: string | null;
  executingActionId: string | null;
};

export function useActionButtons(
  options: UseActionButtonsOptions,
): UseActionButtonsResult {
  const {
    actions,
    onAction,
    onBeforeAction,
    confirmTimeout = 3000,
  } = options;

  const [confirmingActionId, setConfirmingActionId] = useState<string | null>(
    null,
  );
  const [executingActionId, setExecutingActionId] = useState<string | null>(
    null,
  );

  useEffect(() => {
    if (!confirmingActionId) return;
    const id = setTimeout(() => setConfirmingActionId(null), confirmTimeout);
    return () => clearTimeout(id);
  }, [confirmingActionId, confirmTimeout]);

  useEffect(() => {
    if (!confirmingActionId) return;
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === "Escape") {
        setConfirmingActionId(null);
      }
    };

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [confirmingActionId]);

  const runAction = useCallback(
    async (actionId: string) => {
      const action = actions.find((a) => a.id === actionId);
      if (!action) return;

      const isAnyActionExecuting = executingActionId !== null;
      if (action.disabled || action.loading || isAnyActionExecuting) {
        return;
      }

      if (action.confirmLabel && confirmingActionId !== action.id) {
        setConfirmingActionId(action.id);
        return;
      }

      if (onBeforeAction) {
        const shouldProceed = await onBeforeAction(action.id);
        if (!shouldProceed) {
          setConfirmingActionId(null);
          return;
        }
      }

      try {
        setExecutingActionId(action.id);
        await onAction(action.id);
      } finally {
        setExecutingActionId(null);
        setConfirmingActionId(null);
      }
    },
    [actions, confirmingActionId, executingActionId, onAction, onBeforeAction],
  );

  const resolvedActions = useMemo(
    () =>
      actions.map((action) => {
        const isConfirming = confirmingActionId === action.id;
        const isThisActionExecuting = executingActionId === action.id;
        const isLoading = action.loading || isThisActionExecuting;
        const isDisabled =
          action.disabled || (executingActionId !== null && !isThisActionExecuting);
        const currentLabel =
          isConfirming && action.confirmLabel
            ? action.confirmLabel
            : action.label;

        return {
          ...action,
          currentLabel,
          isConfirming,
          isExecuting: isThisActionExecuting,
          isDisabled,
          isLoading,
        };
      }),
    [actions, confirmingActionId, executingActionId],
  );

  return {
    actions: resolvedActions,
    runAction,
    confirmingActionId,
    executingActionId,
  };
}

"use client";

import { useCallback, useEffect, useState } from "react";

function fallbackCopyToClipboard(text: string): boolean {
  try {
    const textArea = document.createElement("textarea");
    textArea.value = text;
    textArea.setAttribute("readonly", "");
    textArea.style.position = "fixed";
    textArea.style.top = "-9999px";
    textArea.style.left = "-9999px";
    document.body.appendChild(textArea);
    textArea.select();
    const ok = document.execCommand("copy");
    document.body.removeChild(textArea);
    return ok;
  } catch {
    return false;
  }
}

export function useCopyToClipboard(options?: {
  resetAfterMs?: number;
}): {
  copiedId: string | null;
  copy: (text: string, id?: string) => Promise<boolean>;
} {
  const resetAfterMs = options?.resetAfterMs ?? 2000;
  const [copiedId, setCopiedId] = useState<string | null>(null);

  const copy = useCallback(
    async (text: string, id: string = "default") => {
      let ok = false;
      try {
        if (navigator.clipboard?.writeText) {
          await navigator.clipboard.writeText(text);
          ok = true;
        } else {
          ok = fallbackCopyToClipboard(text);
        }
      } catch {
        ok = fallbackCopyToClipboard(text);
      }

      if (ok) {
        setCopiedId(id);
      }

      return ok;
    },
    [],
  );

  useEffect(() => {
    if (!copiedId) return;
    const timeout = setTimeout(() => setCopiedId(null), resetAfterMs);
    return () => clearTimeout(timeout);
  }, [copiedId, resetAfterMs]);

  return { copiedId, copy };
}

export function formatRelativeTime(iso: string): string {
  const seconds = Math.round((Date.now() - new Date(iso).getTime()) / 1000);
  if (seconds < 60) return `${seconds}s`;
  if (seconds < 3600) return `${Math.round(seconds / 60)}m`;
  if (seconds < 86400) return `${Math.round(seconds / 3600)}h`;
  if (seconds < 604800) return `${Math.round(seconds / 86400)}d`;
  return `${Math.round(seconds / 604800)}w`;
}

export function formatCount(count: number): string {
  if (count >= 1_000_000) return `${(count / 1_000_000).toFixed(1)}M`;
  if (count >= 1_000) return `${(count / 1_000).toFixed(1)}K`;
  return String(count);
}

export function getDomain(url: string): string {
  try {
    return new URL(url).hostname.replace(/^www\./, "");
  } catch {
    return "";
  }
}

export function prefersReducedMotion(): boolean {
  return (
    typeof window !== "undefined" &&
    window.matchMedia?.("(prefers-reduced-motion: reduce)").matches
  );
}

import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}
